inline fun <reified T> printType(value: Any) {
    if (value is T) println("Value is of type ${T::class}")
}

printType<String>("Hello") // Output: Value is of type class kotlin.String

fun multiplier(factor: Int): (Int) -> Int = { it * factor }
val double = multiplier(2)
println(double(5)) // 10

val sum: (Int, Int) -> Int = { a, b -> a + b }
println(sum(5, 3)) // 8

val square: (Int) -> Int = { it * it }
println(square(4)) // 16

fun String.addExclamation(): String {
    return this + "!"
}

val message = "Hello".addExclamation()
println(message) // Output: Hello!

